public void build()
{
    contract            = this.dataContractObject() as ETGImportInputVATReportContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGImportInputVATReportContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGImportInputVATReportContract, parmToDate), contract);
    vendAccount         = this.addDialogField(methodStr(ETGImportInputVATReportContract, parmVendAccount), contract);
}

public void postBuild()
{
    Dialog dialogobj = this.dialog();

    super();
    dialogFromDate     = this.bindInfo().getDialogField(contract, methodStr(ETGImportInputVATReportContract, parmFromDate));
    dialogToDate       = this.bindInfo().getDialogField(contract, methodStr(ETGImportInputVATReportContract, parmToDate));
    vendAccount        = this.bindInfo().getDialogField(contract, methodStr(ETGImportInputVATReportContract, parmVendAccount));

}

